B.aZ=new A.n8("\u0130spat ve Deliller",B.A7,0,"ispatDeliller")
B.DE=s(["T\xfcm hukuki i\u015flemler, miktar\u0131 ne olursa olsun senetle ispatlanmal\u0131d\u0131r.","Belirli bir parasal s\u0131n\u0131r\u0131 a\u015fan hukuki i\u015flemler kural olarak senetle ispatlanmal\u0131d\u0131r.","Hukuki i\u015flemler her zaman tan\u0131kla ispatlanabilir.","Senetle ispat yaln\u0131zca ticari i\u015flerde zorunludur."],t.s)
B.Jk=new A.bg("ispat_01",B.aZ,"Senetle ispat zorunlulu\u011fu (HMK m. 200) bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi do\u011frudur?",B.DE,1,"HMK m. 200: Bir hakk\u0131n do\u011fumu, d\xfc\u015f\xfcr\xfclmesi vb. amac\u0131yla yap\u0131lan ve belirli bir parasal s\u0131n\u0131r\u0131 a\u015fan hukuki i\u015flemlerin senetle ispat\u0131 zorunludur; bu s\u0131n\u0131r\u0131n alt\u0131ndaki i\u015flemler tan\u0131kla da ispatlanabilir.")
B.DH=s(["Sabittir, yaln\u0131zca kanun de\u011fi\u015fikli\u011fiyle artar.","Her takvim y\u0131l\u0131 ba\u015f\u0131nda yeniden de\u011ferleme oran\u0131nda art\u0131r\u0131l\u0131r.","H\xe2kim her dava i\xe7in ayr\u0131ca takdir eder.","Taraflar s\xf6zle\u015fmeyle serbest\xe7e belirler."],t.s)
B.Jd=new A.bg("ispat_02",B.aZ,"Senetle ispat zorunlulu\u011fundaki parasal s\u0131n\u0131r nas\u0131l belirlenir?",B.DH,1,"S\u0131n\u0131r her takvim y\u0131l\u0131 ba\u015f\u0131ndan ge\xe7erli olmak \xfczere \xf6nceki y\u0131la ili\u015fkin yeniden de\u011ferleme oran\u0131nda art\u0131r\u0131l\u0131r. G\xfcncel TL tutar\u0131n\u0131 ilgili y\u0131l\u0131n oran\u0131na g\xf6re teyit et.")
B.DL=s(["Her h\xe2lde tan\u0131kla ispatlanabilir.","Miktar\u0131na bak\u0131lmaks\u0131z\u0131n senetle ispatlanmas\u0131 gerekir; tan\u0131k dinlenemez.","Yaln\u0131zca yeminle ispatlan\u0131r.","Hi\xe7bir \u015fekilde ispatlanamaz."],t.s)
B.Jp=new A.bg("ispat_03",B.aZ,'Senede ba\u011fl\u0131 bir iddiaya kar\u015f\u0131 ileri s\xfcr\xfclen "senede ayk\u0131r\u0131" bir savunma, s\u0131n\u0131r\u0131n alt\u0131nda kalsa bile nas\u0131l ispatlan\u0131r?',B.DL,1,"HMK m. 201 (senede kar\u015f\u0131 tan\u0131kla ispat yasa\u011f\u0131): Senede ba\u011fl\u0131 her t\xfcr iddiaya kar\u015f\u0131 ileri s\xfcr\xfclen ve senedin h\xfck\xfcm ve kuvvetini ortadan kald\u0131racak/azaltacak iddialar, miktar ne olursa olsun tan\u0131kla ispatlanamaz.")
B.F7=s(["Hi\xe7bir delil kabul edilmez.","Tan\u0131k dinlenebilir.","Dava reddedilir.","Yaln\u0131zca bilirki\u015fi incelemesi yap\u0131l\u0131r."],t.s)
B.Jy=new A.bg("ispat_04",B.aZ,'Senetle ispat zorunlulu\u011fu bulunan bir h\xe2lde "delil ba\u015flang\u0131c\u0131" varsa sonu\xe7 ne olur?',B.F7,1,"HMK m. 202: Delil ba\u015flang\u0131c\u0131 varsa tan\u0131k dinlenebilir. Delil ba\u015flang\u0131c\u0131; iddia edilen i\u015flemi tamamen ispata yetmemekle birlikte onu muhtemel g\xf6steren ve aleyhine ileri s\xfcr\xfclen ki\u015fi (veya temsilcisi) taraf\u0131ndan verilmi\u015f yaz\u0131l\u0131 belgedir.")
B.Fc=s(["\u0130ki tacir aras\u0131ndaki yaz\u0131l\u0131 s\xf6zle\u015fmede","Altsoy\u2013\xfcstsoy, e\u015fler ve karde\u015fler aras\u0131ndaki i\u015flemlerde","Resm\xee senede dayanan alacaklarda","Noterde d\xfczenlenen i\u015flemlerde"],t.s)
B.Ja=new A.bg("ispat_05",B.aZ,"A\u015fa\u011f\u0131dakilerden hangisinde senetle ispat zorunlulu\u011funa ra\u011fmen tan\u0131k dinlenebilir?",B.Fc,1,"HMK m. 203: Altsoy-\xfcstsoy, e\u015fler, karde\u015fler aras\u0131ndaki i\u015flemler; hukuki i\u015flemlerde irade fesad\u0131 (hata, hile, ikrah) iddialar\u0131; haks\u0131z fiil ve sebepsiz zenginle\u015fme; senedin elde tutulamamas\u0131nda hakl\u0131 sebep gibi h\xe2llerde tan\u0131k dinlenebilir.")
B.Fh=s(["Kamu d\xfczenindendir; h\xe2kim resen g\xf6zetir ve taraf vazge\xe7emez.","Kamu d\xfczeninden de\u011fildir; kar\u015f\u0131 taraf a\xe7\u0131k\xe7a muvafakat ederse tan\u0131k dinlenebilir.","Yaln\u0131zca daval\u0131 lehine getirilmi\u015f bir kurald\u0131r.","Sadece istinaf a\u015famas\u0131nda ileri s\xfcr\xfclebilir."],t.s)
B.JC=new A.bg("ispat_06",B.aZ,"Senetle ispat kural\u0131n\u0131n kamu d\xfczeniyle ili\u015fkisi bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi do\u011frudur?",B.Fh,1,"HMK m. 200/2: Senetle ispat zorunlulu\u011fu kamu d\xfczeninden de\u011fildir. Kar\u015f\u0131 taraf a\xe7\u0131k muvafakat verirse (tan\u0131k dinlenmesine itiraz etmezse) s\u0131n\u0131r\u0131n \xfczerindeki i\u015flemde dahi tan\u0131k dinlenebilir.")
B.E9=s(["Hi\xe7 kimse tan\u0131kl\u0131ktan \xe7ekinemez.","Taraflardan birinin ni\u015fanl\u0131s\u0131 veya belirli derecedeki h\u0131s\u0131mlar\u0131 tan\u0131kl\u0131ktan \xe7ekinebilir.","Tan\u0131kl\u0131ktan yaln\u0131zca kamu g\xf6revlileri \xe7ekinebilir.","Tan\u0131kl\u0131ktan \xe7ekinme yaln\u0131zca ceza davalar\u0131nda m\xfcmk\xfcnd\xfcr."],t.s)
B.JA=new A.bg("ispat_07",B.aZ,"Tan\u0131kl\u0131ktan \xe7ekinme hakk\u0131 bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi s\xf6ylenebilir?",B.E9,1,"HMK m. 248: \u0130ki taraftan birinin ni\u015fanl\u0131s\u0131; evlilik ba\u011f\u0131 kalmasa da e\u015fi; belirli derecedeki kan ve kay\u0131n h\u0131s\u0131mlar\u0131 ile evlatl\u0131k ba\u011f\u0131 bulunanlar ki\u015fisel sebeplerle tan\u0131kl\u0131ktan \xe7ekinebilir (m. 249\u2013250: s\u0131r ve menfaat ihlali sebepleri ayr\u0131ca d\xfczenlenmi\u015ftir).")
B.CL=s(["Teknik bir konunun ayd\u0131nlat\u0131lmas\u0131 gerekti\u011finde","\xc7\xf6z\xfcm\xfc h\xe2kimlik mesle\u011finin gerektirdi\u011fi genel ve hukuki bilgiyle m\xfcmk\xfcn olan konularda","Hesap ve muhasebe incelemesi gerekti\u011finde","T\u0131bbi bir de\u011ferlendirme gerekti\u011finde"],t.s)
B.Jg=new A.bg("ispat_08",B.aZ,"Bilirki\u015fiye hangi durumda ba\u015fvurulamaz?",B.CL,1,"HMK m. 266: \xc7\xf6z\xfcm\xfc \xf6zel/teknik bilgiyi gerektiren h\xe2llerde bilirki\u015fiye ba\u015fvurulur; ancak genel bilgi veya hukuki bilgiyle \xe7\xf6z\xfclebilecek konularda (hukukun uygulanmas\u0131 h\xe2kime ait oldu\u011fundan) bilirki\u015fiye ba\u015fvurulamaz.")
B.DJ=s(["Bir hafta","\u0130ki hafta","Bir ay","On g\xfcn"],t.s)
B.Jm=new A.bg("ispat_09",B.aZ,"Bilirki\u015fi raporuna kar\u015f\u0131, raporun tebli\u011finden itibaren itiraz s\xfcresi ne kadard\u0131r?",B.DJ,1,"HMK m. 281: Taraflar, raporun kendilerine tebli\u011finden itibaren iki hafta i\xe7inde itiraz edebilir; eksikliklerin tamamlanmas\u0131n\u0131, belirsizliklerin giderilmesini veya yeni bilirki\u015fi atanmas\u0131n\u0131 isteyebilirler.")
B.DK=s(["Rapor kesin delildir; h\xe2kim aynen uymak zorundad\u0131r.","Rapor takdiri delildir; h\xe2kim raporla ba\u011fl\u0131 de\u011fildir, serbest\xe7e de\u011ferlendirir.","H\xe2kim raporu hi\xe7 dikkate alamaz.","H\xe2kim ancak Yarg\u0131tay onay\u0131yla rapordan ayr\u0131labilir."],t.s)
B.J4=new A.bg("ispat_10",B.aZ,"H\xe2kimin bilirki\u015fi raporu kar\u015f\u0131s\u0131ndaki durumu nedir?",B.DK,1,"Bilirki\u015fi raporu takdiri delildir. H\xe2kim raporu serbest\xe7e de\u011ferlendirir ve gerek\xe7esini g\xf6stererek rapordan ayr\u0131labilir; ayr\u0131ca bilirki\u015fi hukuki nitelendirme yapamaz, hukukun uygulanmas\u0131 h\xe2kime aittir.")
B.zV=new A.K(1,0.9490196078431372,0.6392156862745098,0.23529411764705882,B.f)
B.bZ=new A.n8("Ge\xe7ici Hukuki Korumalar",B.zV,1,"geciciKoruma")
B.Eh=s(["Para alacaklar\u0131n\u0131n tahsilinin g\xfcvence alt\u0131na al\u0131nmas\u0131","Uyu\u015fmazl\u0131k konusu (\xe7eki\u015fmeli) \u015fey veya hak hakk\u0131nda koruma sa\u011flanmas\u0131","Bor\xe7lunun hapsen tazyiki","Kesinle\u015fmi\u015f bir karar\u0131n icras\u0131"],t.s)
B.JB=new A.bg("gecici_01",B.bZ,"\u0130htiyati tedbirin konusu a\u015fa\u011f\u0131dakilerden hangisidir?",B.Eh,1,"HMK m. 389: \u0130htiyati tedbir, uyu\u015fmazl\u0131k konusu \u015fey/hak hakk\u0131nda; mevcut durumdaki de\u011fi\u015fme nedeniyle hakka kavu\u015fman\u0131n zorla\u015faca\u011f\u0131/imk\xe2ns\u0131zla\u015faca\u011f\u0131 ya da gecikme y\xfcz\xfcnden ciddi zarar do\u011faca\u011f\u0131 h\xe2llerde verilir. Para alacaklar\u0131n\u0131n g\xfcvencesi ise ihtiyati hacizdir.")
