B.JD=new A.bg("gecici_02",B.bZ,"\u0130htiyati haciz hangi t\xfcr alacaklar i\xe7in istenir ve dayana\u011f\u0131 hangi kanundur?",B.EK,1,"\u0130\u0130K m. 257: \u0130htiyati haciz, rehinle temin edilmemi\u015f ve vadesi gelmi\u015f bir para borcunun alacakl\u0131s\u0131 taraf\u0131ndan istenir (kanunda say\u0131lan h\xe2llerde vadesi gelmemi\u015f alacaklar i\xe7in de m\xfcmk\xfcnd\xfcr). Dayana\u011f\u0131 \u0130cra ve \u0130flas Kanunu\u2019dur.")
B.Dn=s(["\u0130kisi de yaln\u0131zca para alacaklar\u0131 i\xe7indir.","\u0130htiyati tedbir \xe7eki\u015fmeli \u015fey/hak i\xe7in (HMK), ihtiyati haciz para alaca\u011f\u0131 i\xe7in (\u0130\u0130K) \xf6ng\xf6r\xfclm\xfc\u015ft\xfcr.","\u0130htiyati haciz dava a\xe7\u0131lmadan hi\xe7 istenemez.","\u0130htiyati tedbir yaln\u0131zca icra dairesinden istenir."],t.s)
B.Js=new A.bg("gecici_03",B.bZ,"\u0130htiyati tedbir ile ihtiyati haciz aras\u0131ndaki temel fark a\u015fa\u011f\u0131dakilerden hangisidir?",B.Dn,1,"Temel ayr\u0131m konular\u0131ndad\u0131r: \u0130htiyati tedbir para d\u0131\u015f\u0131ndaki \xe7eki\u015fmeli \u015fey/hakk\u0131n korunmas\u0131na (HMK m. 389 vd.), ihtiyati haciz ise para alaca\u011f\u0131n\u0131n g\xfcvenceye al\u0131nmas\u0131na (\u0130\u0130K m. 257 vd.) hizmet eder.")
B.DY=s(["Hakl\u0131l\u0131\u011f\u0131n\u0131 tam (kesin) olarak ispatlamal\u0131d\u0131r.","Hakl\u0131l\u0131\u011f\u0131n\u0131 yakla\u015f\u0131k olarak ispat etmelidir.","Hi\xe7bir ispat y\xfck\xfc yoktur.","Yaln\u0131zca yemin etmesi yeterlidir."],t.s)
B.Ju=new A.bg("gecici_04",B.bZ,"\u0130htiyati tedbir talep eden, talebinin hakl\u0131l\u0131\u011f\u0131 bak\u0131m\u0131ndan neyi yerine getirmelidir?",B.DY,1,"HMK m. 390/3: \u0130htiyati tedbir isteyen, davan\u0131n esas\u0131 y\xf6n\xfcnden kendisinin hakl\u0131 oldu\u011funu yakla\u015f\u0131k olarak ispat etmek zorundad\u0131r (tam ispat aranmaz).")
