B.Jn=new A.bg("gecici_06",B.bZ,"Dava a\xe7\u0131lmadan \xf6nce ihtiyati tedbir karar\u0131 al\u0131nm\u0131\u015fsa, esas hakk\u0131nda dava ne kadar s\xfcrede a\xe7\u0131lmal\u0131d\u0131r?",B.Fa,1,"HMK m. 397/1: Dava a\xe7\u0131lmadan \xf6nce verilen ihtiyati tedbirde, tedbir karar\u0131n\u0131n uygulanmas\u0131n\u0131 isteme tarihinden itibaren iki hafta i\xe7inde esas hakk\u0131nda dava a\xe7\u0131lmazsa tedbir kendili\u011finden kalkar.")
B.Ek=s(["Yedi g\xfcn i\xe7inde","\u0130ki hafta i\xe7inde","Bir ay i\xe7inde","\xdc\xe7 ay i\xe7inde"],t.s)
