B.DB=s(["\u0130stinaf mercii Yarg\u0131tay, temyiz mercii b\xf6lge adliye mahkemesidir.","\u0130stinaf mercii b\xf6lge adliye mahkemesi (BAM), temyiz mercii Yarg\u0131tay\u2019d\u0131r.","Her iki kanun yolu da do\u011frudan Yarg\u0131tay\u2019da incelenir.","Her iki kanun yolu da ilk derece mahkemesinde incelenir."],t.s)
