B.EM=s(["Daval\u0131n\u0131n, davac\u0131n\u0131n talep sonucunu kabul etmesidir.","Davac\u0131n\u0131n, talep sonucundan (netice-i talepten) k\u0131smen veya tamamen vazge\xe7mesidir.","Taraflar\u0131n kar\u015f\u0131l\u0131kl\u0131 anla\u015fmas\u0131d\u0131r.","H\xe2kimin davay\u0131 reddetmesidir."],t.s)
B.Ji=new A.bg("taraf_01",B.c_,"Feragat nedir?",B.EM,1,"HMK m. 307: Feragat, davac\u0131n\u0131n talep sonucundan k\u0131smen veya tamamen vazge\xe7mesidir.")
B.DZ=s(["Davac\u0131n\u0131n davas\u0131ndan vazge\xe7mesidir.","Daval\u0131n\u0131n, davac\u0131n\u0131n talep sonucuna k\u0131smen veya tamamen muvafakat etmesidir.","Taraflar\u0131n uzla\u015fmas\u0131d\u0131r.","Mahkemenin davay\u0131 kabul etmesidir."],t.s)
B.Jq=new A.bg("taraf_02",B.c_,"Kabul nedir?",B.DZ,1,"HMK m. 308: Kabul, davac\u0131n\u0131n talep sonucuna daval\u0131n\u0131n k\u0131smen veya tamamen muvafakat etmesidir.")
B.EL=s(["Evet, her ikisi de kar\u015f\u0131 taraf\u0131n kabul\xfcne ba\u011fl\u0131d\u0131r.","Hay\u0131r; feragat ve kabul tek tarafl\u0131 irade beyan\u0131yla sonu\xe7 do\u011furur, kar\u015f\u0131 taraf\u0131n veya mahkemenin muvafakatine gerek yoktur.","Yaln\u0131zca h\xe2kimin onay\u0131yla ge\xe7erli olur.","Yaln\u0131zca noter huzurunda yap\u0131l\u0131rsa ge\xe7erlidir."],t.s)
B.Jh=new A.bg("taraf_03",B.c_,"Feragat ve kabul\xfcn ge\xe7erlili\u011fi i\xe7in kar\u015f\u0131 taraf\u0131n veya mahkemenin onay\u0131 gerekir mi?",B.EL,1,"HMK m. 309/1: Feragat ve kabul, dilek\xe7eyle veya yarg\u0131lama s\u0131ras\u0131nda s\xf6zl\xfc olarak yap\u0131l\u0131r; kar\u015f\u0131 taraf\u0131n ya da mahkemenin muvafakatine ba\u011fl\u0131 de\u011fildir (tek tarafl\u0131 i\u015flemlerdir).")
B.Eb=s(["Davay\u0131 durdurur ama sona erdirmez.","Kesin h\xfck\xfcm gibi sonu\xe7 do\u011furur ve davay\u0131 sona erdirir.","Yaln\u0131zca delil de\u011feri ta\u015f\u0131r.","Davan\u0131n istinafa ta\u015f\u0131nmas\u0131n\u0131 sa\u011flar."],t.s)
B.Jt=new A.bg("taraf_04",B.c_,"Feragat, kabul ve (mahkeme i\xe7i) sulhun davaya etkisi nedir?",B.Eb,1,"HMK m. 311: Feragat ve kabul, kesin h\xfck\xfcm gibi hukuki sonu\xe7 do\u011furur. Mahkeme i\xe7i sulh de ayn\u0131 \u015fekilde davay\u0131 sona erdirir ve kesin h\xfck\xfcm gibi sonu\xe7 do\u011furur.")
B.Do=s(["Hi\xe7bir gider \xf6demez.","Davay\u0131 kaybetmi\u015f gibi yarg\u0131lama giderlerini \xf6demekle y\xfck\xfcml\xfc olur.","Giderlerin tamam\u0131 daval\u0131ya y\xfckletilir.","Giderler devlet hazinesinden kar\u015f\u0131lan\u0131r."],t.s)
B.J8=new A.bg("taraf_05",B.c_,"Davadan feragat eden davac\u0131n\u0131n yarg\u0131lama giderleri bak\u0131m\u0131ndan durumu nedir?",B.Do,1,"HMK m. 312: Feragat veya kabul h\xe2linde, feragat eden davac\u0131 ya da kabul eden daval\u0131, davada aleyhine h\xfck\xfcm verilmi\u015f gibi yarg\u0131lama giderlerini \xf6demeye mahk\xfbm edilir.")
B.F3=s(["Yine de t\xfcm giderleri \xf6der.","Yarg\u0131lama giderlerini \xf6demeye mahk\xfbm edilmez.","Giderlerin yar\u0131s\u0131n\u0131 \xf6der.","Dava reddedilir."],t.s)
B.Jw=new A.bg("taraf_06",B.c_,"Daval\u0131, davan\u0131n a\xe7\u0131lmas\u0131na kendi davran\u0131\u015f\u0131yla sebep olmam\u0131\u015f ve davac\u0131n\u0131n talebini ilk duru\u015fmada kabul etmi\u015fse yarg\u0131lama giderleri bak\u0131m\u0131ndan sonu\xe7 nedir?",B.F3,1,"HMK m. 312/2: Daval\u0131, davan\u0131n a\xe7\u0131lmas\u0131na kendi h\xe2l ve davran\u0131\u015f\u0131yla sebebiyet vermemi\u015f ve davac\u0131n\u0131n iddialar\u0131n\u0131 ilk duru\u015fmada kabul etmi\u015fse yarg\u0131lama giderlerini \xf6demeye mahk\xfbm edilmez.")
B.F6=s(["Sulh tek tarafl\u0131 bir i\u015flemdir.","Sulh iki tarafl\u0131 (kar\u015f\u0131l\u0131kl\u0131) bir i\u015flemdir; taraflar\u0131n anla\u015fmas\u0131yla kurulur.","Sulh yaln\u0131zca istinaf a\u015famas\u0131nda yap\u0131labilir.","Sulh hi\xe7bir zaman kesin h\xfck\xfcm do\u011furmaz."],t.s)
B.Jf=new A.bg("taraf_07",B.c_,"Sulhun feragat ve kabulden ayr\u0131lan en belirgin \xf6zelli\u011fi nedir?",B.F6,1,"Feragat ve kabul tek tarafl\u0131 i\u015flemlerken sulh, taraflar\u0131n kar\u015f\u0131l\u0131kl\u0131 anla\u015fmas\u0131na dayanan iki tarafl\u0131 bir i\u015flemdir (HMK m. 313 vd.). Yarg\u0131lama giderleri kural olarak taraflar\u0131n anla\u015fmas\u0131na g\xf6re; anla\u015fma yoksa e\u015fit olarak payla\u015ft\u0131r\u0131l\u0131r.")
